import { Card, CardHeader, CardTitle, CardBody, Button } from "reactstrap";

import React from "react";
import { useHistory } from "react-router-dom";
import TableComponent from "../common/TableComponent";
import { apiBaseUrl } from "../../urlConstants";
export const taColumns = [
  {
    name: "Truck Number",
    selector: "VEHICAL_NO",
    sortable: true,
    minWidth: "150px",
  },
  {
    name: "Loading point",
    selector: "ZSUPPLIER_LOAD_POINT",
    sortable: true,
    minWidth: "150px",
  },
  {
    name: "Loading date",
    selector: "ZSUPPLIER_LOAD_DT",
    sortable: true,
    minWidth: "150px",
  },
  {
    name: "Plant Name",
    selector: "PLANT_NAME",
    sortable: true,
    minWidth: "230px",
  },
  {
    name: "EDA",
    selector: "EDA",
    sortable: true,
    minWidth: "150px",
  },
];

const SdiRedirectList = () => {
  const history = useHistory();
  const actionsCol = {
    name: "Actions",
    selector: "Edit",
    minWidth: "150px",
    cell: (row) => {
      return (
        <Button.Ripple
          color="primary"
          onClick={(e) => {
            history.push(`/SDIR:${row.SUP_VE_REFID}`);
          }}
        >
          {"Edit"}
        </Button.Ripple>
      );
    },
  };
  const columns = [...taColumns, actionsCol];
  return (
    <div>
      <Card>
        <CardHeader>
          <CardTitle>{"Supplier Dispatch Redirect"}</CardTitle>
        </CardHeader>
        <CardBody>
          <TableComponent postData={{}} columns={columns} url={apiBaseUrl + "sdi/getsdiVehicleList"} />
        </CardBody>
      </Card>
    </div>
  );
};

export default SdiRedirectList;
